B.J_=s(["    CREATE TABLE companies (\n      id INTEGER PRIMARY KEY AUTOINCREMENT,\n      official_name TEXT NOT NULL,\n      common_name TEXT NOT NULL,\n      ticker_symbol TEXT,\n      founded_year INTEGER NOT NULL,\n      founded_month INTEGER,\n      headquarters_city TEXT NOT NULL,\n      headquarters_country TEXT NOT NULL,\n      current_ceo TEXT,\n      employee_count INTEGER,\n      employee_count_year INTEGER,\n      revenue_usd INTEGER,\n      revenue_year INTEGER,\n      market_cap_usd INTEGER,\n      primary_focus TEXT NOT NULL,\n      key_technologies TEXT,\n      notable_customers TEXT,\n      careers_url TEXT,\n      official_website TEXT,\n      short_description TEXT NOT NULL,\n      founder_names TEXT,\n      logo_url TEXT,\n      domain TEXT,              -- \u2705 \u0627\u0644\u0639\u0645\u0648\u062f \u0627\u0644\u062c\u062f\u064a\u062f (\u0644\u0634\u0639\u0627\u0631\u0627\u062a Clearbit)\n      created_at TEXT NOT NULL,\n      updated_at TEXT NOT NULL\n    )\n  ","    CREATE TABLE technology_nodes (\n      id INTEGER PRIMARY KEY AUTOINCREMENT,\n      node_name TEXT NOT NULL UNIQUE,\n      size_nm REAL,\n      introduction_year INTEGER NOT NULL,\n      is_volume_production INTEGER DEFAULT 0,\n      description TEXT,\n      created_at TEXT NOT NULL,\n      updated_at TEXT NOT NULL\n    )\n  ","    CREATE TABLE products (\n      id INTEGER PRIMARY KEY AUTOINCREMENT,\n      company_id INTEGER NOT NULL,\n      product_name TEXT NOT NULL,\n      category TEXT,\n      description TEXT,\n      release_year INTEGER,\n      node_id INTEGER,\n      created_at TEXT NOT NULL,\n      updated_at TEXT NOT NULL,\n      FOREIGN KEY (company_id) REFERENCES companies(id) ON DELETE CASCADE,\n      FOREIGN KEY (node_id) REFERENCES technology_nodes(id) ON DELETE SET NULL\n    )\n  ","    CREATE TABLE company_node_history (\n      id INTEGER PRIMARY KEY AUTOINCREMENT,\n      company_id INTEGER NOT NULL,\n      node_id INTEGER NOT NULL,\n      adoption_year INTEGER NOT NULL,\n      product_example TEXT,\n      notes TEXT,\n      created_at TEXT NOT NULL,\n      updated_at TEXT NOT NULL,\n      FOREIGN KEY (company_id) REFERENCES companies(id) ON DELETE CASCADE,\n      FOREIGN KEY (node_id) REFERENCES technology_nodes(id) ON DELETE CASCADE\n    )\n  ","    CREATE TABLE industry_events (\n      id INTEGER PRIMARY KEY AUTOINCREMENT,\n      event_title TEXT NOT NULL,\n      event_description TEXT,\n      event_date TEXT NOT NULL,\n      event_category TEXT,\n      is_major INTEGER DEFAULT 0,\n      related_company_id INTEGER,\n      created_at TEXT NOT NULL,\n      updated_at TEXT NOT NULL,\n      FOREIGN KEY (related_company_id) REFERENCES companies(id) ON DELETE SET NULL\n    )\n  ","    CREATE TABLE careers_roles (\n      id INTEGER PRIMARY KEY AUTOINCREMENT,\n      role_title TEXT NOT NULL UNIQUE,\n      category TEXT NOT NULL,\n      description TEXT,\n      required_skills TEXT,\n      created_at TEXT NOT NULL,\n      updated_at TEXT NOT NULL\n    )\n  ","    CREATE TABLE company_careers (\n      id INTEGER PRIMARY KEY AUTOINCREMENT,\n      company_id INTEGER NOT NULL,\n      role_id INTEGER NOT NULL,\n      careers_url_specific TEXT,\n      created_at TEXT NOT NULL,\n      updated_at TEXT NOT NULL,\n      FOREIGN KEY (company_id) REFERENCES companies(id) ON DELETE CASCADE,\n      FOREIGN KEY (role_id) REFERENCES careers_roles(id) ON DELETE CASCADE,\n      UNIQUE (company_id, role_id)\n    )\n  ","    CREATE TABLE bookmarks (\n      id INTEGER PRIMARY KEY AUTOINCREMENT,\n      entity_type TEXT NOT NULL CHECK(entity_type IN ('company', 'event', 'role')),\n      entity_id INTEGER NOT NULL,\n      note TEXT,\n      created_at TEXT NOT NULL,\n      UNIQUE (entity_type, entity_id)\n    )\n  ","CREATE INDEX idx_companies_country ON companies(headquarters_country)","CREATE INDEX idx_companies_founded_year ON companies(founded_year)","CREATE INDEX idx_companies_revenue ON companies(revenue_usd)","CREATE INDEX idx_products_company ON products(company_id)","CREATE INDEX idx_products_release_year ON products(release_year)","CREATE INDEX idx_nodes_introduction_year ON technology_nodes(introduction_year)","CREATE INDEX idx_node_history_company ON company_node_history(company_id)","CREATE INDEX idx_node_history_node ON company_node_history(node_id)","CREATE INDEX idx_node_history_year ON company_node_history(adoption_year)","CREATE INDEX idx_events_date ON industry_events(event_date)","CREATE INDEX idx_events_category ON industry_events(event_category)","CREATE INDEX idx_careers_category ON careers_roles(category)","CREATE INDEX idx_company_careers_company ON company_careers(company_id)","CREATE INDEX idx_company_careers_role ON company_careers(role_id)","CREATE INDEX idx_bookmarks_entity ON bookmarks(entity_type, entity_id)","CREATE INDEX idx_companies_search ON companies(common_name, official_name, primary_focus, short_description)","CREATE INDEX idx_events_search ON industry_events(event_title, event_description, event_category)","CREATE INDEX idx_careers_search ON careers_roles(role_title, category, description, required_skills)"],t.s)
